<template>
  <div class="learning-paths">
    <div class="page-header">
      <div>
        <h2 class="page-title">学习路径</h2>
        <p class="page-subtitle">系统化学习路线，覆盖主流技术栈</p>
      </div>
      <!-- 筛选 -->
      <div class="filter-bar">
        <el-select v-model="difficultyFilter" placeholder="难度" size="small" clearable @change="filterPaths">
          <el-option label="全部" value="" />
          <el-option label="入门" value="BEGINNER" />
          <el-option label="进阶" value="INTERMEDIATE" />
          <el-option label="高级" value="ADVANCED" />
        </el-select>
        <el-select v-model="sortBy" placeholder="排序" size="small" @change="filterPaths">
          <el-option label="默认排序" value="default" />
          <el-option label="课程最多" value="courses" />
          <el-option label="天数最多" value="days" />
        </el-select>
      </div>
    </div>

    <!-- 推荐路径 -->
    <section v-if="recommendedPaths.length > 0" class="section-block">
      <div class="section-label-row">
        <span class="section-label-icon">🌟</span>
        <h3>为你推荐</h3>
      </div>
      <div class="path-grid">
        <div v-for="path in recommendedPaths" :key="path.id" class="path-card" @click="$router.push(`/learning-paths/${path.id}`)">
          <div class="path-card-header" :style="{ background: pathGradient(path.difficulty) }">
            <span class="path-diff-badge">{{ diffLabel(path.difficulty) }}</span>
            <span class="path-course-badge">{{ path.courseCount }} 课程</span>
          </div>
          <div class="path-card-body">
            <h3 class="path-card-title">{{ path.title }}</h3>
            <p class="path-card-desc">{{ path.description }}</p>
            <div class="path-card-tags">
              <span v-for="tag in (path.tags || []).slice(0, 4)" :key="tag" class="path-tag">{{ tag }}</span>
            </div>
            <div class="path-card-footer">
              <span class="path-days"><i class="el-icon-time"></i> {{ path.estimatedDays }} 天</span>
              <span class="path-updated">更新于 {{ formatDate(path.updateTime) }}</span>
            </div>
          </div>
        </div>
      </div>
    </section>

    <!-- 全部路径 -->
    <section class="section-block">
      <div class="section-label-row">
        <span class="section-label-icon">📚</span>
        <h3>全部路径 ({{ displayPaths.length }})</h3>
      </div>
      <div v-if="displayPaths.length === 0" class="empty-state">
        <div class="empty-icon">📖</div>
        <p>暂无学习路径</p>
      </div>
      <div v-else class="path-grid">
        <div v-for="(path, idx) in displayPaths" :key="path.id" class="path-card animate-fade-in-up" :style="{ animationDelay: `${idx * 0.05}s` }" @click="$router.push(`/learning-paths/${path.id}`)">
          <div class="path-card-header" :style="{ background: pathGradient(path.difficulty) }">
            <span class="path-diff-badge">{{ diffLabel(path.difficulty) }}</span>
            <span class="path-course-badge">{{ path.courseCount }} 课程</span>
          </div>
          <div class="path-card-body">
            <h3 class="path-card-title">{{ path.title }}</h3>
            <p class="path-card-desc">{{ path.description }}</p>
            <div class="path-card-tags">
              <span v-for="tag in (path.tags || []).slice(0, 4)" :key="tag" class="path-tag">{{ tag }}</span>
            </div>
            <div class="path-card-footer">
              <span class="path-days"><i class="el-icon-time"></i> {{ path.estimatedDays }} 天</span>
              <span class="path-updated">更新于 {{ formatDate(path.updateTime) }}</span>
            </div>
          </div>
        </div>
      </div>
    </section>
  </div>
</template>

<script>
import PathCard from '../components/PathCard.vue';
import { learningPathApi } from '../api';
import { mockLearningPaths, fallbackArray } from '../mock';

export default {
  name: 'LearningPaths',
  components: { PathCard },
  data() {
    return {
      allPaths: [],
      recommendedPaths: [],
      difficultyFilter: '',
      sortBy: 'default'
    };
  },
  computed: {
    displayPaths() {
      let paths = fallbackArray(this.allPaths, mockLearningPaths);
      if (this.difficultyFilter) {
        paths = paths.filter(p => p.difficulty === this.difficultyFilter);
      }
      if (this.sortBy === 'courses') {
        paths = [...paths].sort((a, b) => (b.courseCount || 0) - (a.courseCount || 0));
      } else if (this.sortBy === 'days') {
        paths = [...paths].sort((a, b) => (b.estimatedDays || 0) - (a.estimatedDays || 0));
      }
      return paths;
    }
  },
  created() { this.loadData(); },
  methods: {
    async loadData() {
      try {
        const [allRes, recRes] = await Promise.all([
          learningPathApi.getAll(),
          learningPathApi.getRecommended().catch(() => ({ data: [] }))
        ]);
        if (allRes.code === 200) this.allPaths = allRes.data || [];
        if (recRes.code === 200) this.recommendedPaths = recRes.data || [];
        if (this.recommendedPaths.length === 0) {
          this.recommendedPaths = mockLearningPaths.slice(0, 3);
        }
      } catch {
        this.allPaths = [];
      }
    },
    filterPaths() {},
    diffLabel(d) {
      const map = { BEGINNER: '入门', INTERMEDIATE: '进阶', ADVANCED: '高级' };
      return map[d] || d;
    },
    pathGradient(d) {
      const map = {
        BEGINNER: 'linear-gradient(135deg, #059669, #10b981)',
        INTERMEDIATE: 'linear-gradient(135deg, #d97706, #f59e0b)',
        ADVANCED: 'linear-gradient(135deg, #7c3aed, #8b5cf6)'
      };
      return map[d] || 'linear-gradient(135deg, #1a56db, #3b82f6)';
    },
    formatDate(t) {
      if (!t) return '';
      return new Date(t).toLocaleDateString('zh-CN');
    }
  }
};
</script>

